        # 9. Nerede? - Where is the...? [NEW]
        {"title": "Nerede? / Where is the...?", "rule_tr": "Where is the ___? It is on/in/under ___.", "examples": [
            {"en": "Where is the cat? It is on the chair.", "de": "Wo ist die Katze? Sie ist auf dem Stuhl.", "fr": "Ou est le chat? Il est sur la chaise.", "it": "Dov'e il gatto? E sulla sedia.", "es": "Donde esta el gato? Esta en la silla.", "tr": "Kedi nerede? Sandalyenin uzerinde."},
            {"en": "Where is the ball? It is under the table.", "de": "Wo ist der Ball? Er ist unter dem Tisch.", "fr": "Ou est la balle? Elle est sous la table.", "it": "Dov'e la palla? E sotto il tavolo.", "es": "Donde esta la pelota? Esta debajo de la mesa.", "tr": "Top nerede? Masanin altinda."},
            {"en": "Where is the book? It is in the bag.", "de": "Wo ist das Buch? Es ist in der Tasche.", "fr": "Ou est le livre? Il est dans le sac.", "it": "Dov'e il libro? E nella borsa.", "es": "Donde esta el libro? Esta en la bolsa.", "tr": "Kitap nerede? Cantanin icinde."},
            {"en": "Where is the dog? It is in the garden.", "de": "Wo ist der Hund? Er ist im Garten.", "fr": "Ou est le chien? Il est dans le jardin.", "it": "Dov'e il cane? E nel giardino.", "es": "Donde esta el perro? Esta en el jardin.", "tr": "Kopek nerede? Bahcede."},
            {"en": "Where is the bird? It is on the tree.", "de": "Wo ist der Vogel? Er ist auf dem Baum.", "fr": "Ou est l'oiseau? Il est sur l'arbre.", "it": "Dov'e l'uccello? E sull'albero.", "es": "Donde esta el pajaro? Esta en el arbol.", "tr": "Kus nerede? Agacin uzerinde."},
        ], "exercises": [
            {"prompt": "Where is the cat? It is ___ the chair.", "answer": "on", "hint": "Uzerinde"},
            {"prompt": "Where is the ball? It is ___ the table.", "answer": "under", "hint": "Altinda"},
            {"prompt": "Where is the book? It is ___ the bag.", "answer": "in", "hint": "Icinde"},
            {"prompt": "Where is the fish? It is ___ the water.", "answer": "in", "hint": "Icinde"},
            {"prompt": "Where is the bird? It is ___ the tree.", "answer": "on", "hint": "Uzerinde"},
        ]},
